#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <chrono>
#include <cuda_runtime.h>

FILE *fp;

struct Node
{
	int starting;
	int no_of_edges;
};

void BFSGraph(int argc, char** argv);

void Usage(int argc, char**argv)
{
	fprintf(stderr,"Usage: %s <num_threads> <input_file>\n", argv[0]);
}

__global__ void bfs_kernel_phase1(
	int no_of_nodes,
	const Node* graph_nodes,
	const int* graph_edges,
	unsigned char* graph_mask,
	unsigned char* updating_graph_mask,
	const unsigned char* graph_visited,
	int* cost)
{
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes)
	{
		if (graph_mask[tid])
		{
			graph_mask[tid] = 0;
			int start = graph_nodes[tid].starting;
			int end = start + graph_nodes[tid].no_of_edges;
			int next_cost = cost[tid] + 1;
			for (int i = start; i < end; i++)
			{
				int id = graph_edges[i];
				if (!graph_visited[id])
				{
					cost[id] = next_cost;
					updating_graph_mask[id] = 1;
				}
			}
		}
	}
}

__global__ void bfs_kernel_phase2(
	int no_of_nodes,
	unsigned char* graph_mask,
	unsigned char* updating_graph_mask,
	unsigned char* graph_visited,
	int* stop)
{
	int tid = blockIdx.x * blockDim.x + threadIdx.x;
	if (tid < no_of_nodes)
	{
		if (updating_graph_mask[tid])
		{
			graph_mask[tid] = 1;
			graph_visited[tid] = 1;
			*stop = 1;
			updating_graph_mask[tid] = 0;
		}
	}
}

int main(int argc, char** argv)
{
	BFSGraph(argc, argv);
	return 0;
}

void BFSGraph(int argc, char** argv)
{
	int no_of_nodes = 0;
	int edge_list_size = 0;
	char *input_f;
	int num_omp_threads;

	if(argc!=3)
	{
		Usage(argc, argv);
		exit(0);
	}

	num_omp_threads = atoi(argv[1]);
	(void)num_omp_threads;
	input_f = argv[2];

	printf("Reading File\n");

	fp = fopen(input_f,"r");
	if(!fp)
	{
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp,"%d",&no_of_nodes);

	Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
	unsigned char* h_graph_mask = (unsigned char*) malloc(sizeof(unsigned char)*no_of_nodes);
	unsigned char* h_updating_graph_mask = (unsigned char*) malloc(sizeof(unsigned char)*no_of_nodes);
	unsigned char* h_graph_visited = (unsigned char*) malloc(sizeof(unsigned char)*no_of_nodes);

	int start, edgeno;

	for(unsigned int i = 0; i < (unsigned int)no_of_nodes; i++)
	{
		fscanf(fp,"%d %d",&start,&edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i] = 0;
		h_updating_graph_mask[i] = 0;
		h_graph_visited[i] = 0;
	}

	fscanf(fp,"%d",&source);

	h_graph_mask[source] = 1;
	h_graph_visited[source] = 1;

	fscanf(fp,"%d",&edge_list_size);

	int id, cost;
	int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
	for(int i = 0; i < edge_list_size; i++)
	{
		fscanf(fp,"%d",&id);
		fscanf(fp,"%d",&cost);
		h_graph_edges[i] = id;
	}

	if(fp)
		fclose(fp);

	int* h_cost = (int*) malloc(sizeof(int)*no_of_nodes);
	for(int i = 0; i < no_of_nodes; i++)
		h_cost[i] = -1;
	h_cost[source] = 0;

	printf("Start traversing the tree\n");

	Node* d_graph_nodes = NULL;
	int* d_graph_edges = NULL;
	unsigned char* d_graph_mask = NULL;
	unsigned char* d_updating_graph_mask = NULL;
	unsigned char* d_graph_visited = NULL;
	int* d_cost = NULL;
	int* d_stop = NULL;

	if (no_of_nodes > 0)
	{
		cudaMalloc((void**)&d_graph_nodes, sizeof(Node) * no_of_nodes);
		cudaMalloc((void**)&d_graph_mask, sizeof(unsigned char) * no_of_nodes);
		cudaMalloc((void**)&d_updating_graph_mask, sizeof(unsigned char) * no_of_nodes);
		cudaMalloc((void**)&d_graph_visited, sizeof(unsigned char) * no_of_nodes);
		cudaMalloc((void**)&d_cost, sizeof(int) * no_of_nodes);

		cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node) * no_of_nodes, cudaMemcpyHostToDevice);
		cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(unsigned char) * no_of_nodes, cudaMemcpyHostToDevice);
		cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(unsigned char) * no_of_nodes, cudaMemcpyHostToDevice);
		cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(unsigned char) * no_of_nodes, cudaMemcpyHostToDevice);
		cudaMemcpy(d_cost, h_cost, sizeof(int) * no_of_nodes, cudaMemcpyHostToDevice);
	}

	if (edge_list_size > 0)
	{
		cudaMalloc((void**)&d_graph_edges, sizeof(int) * edge_list_size);
		cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * edge_list_size, cudaMemcpyHostToDevice);
	}

	cudaMalloc((void**)&d_stop, sizeof(int));

	int k = 0;
	(void)k;

	auto start_time = std::chrono::high_resolution_clock::now();

	bool stop;
	do
	{
		stop = false;
		int h_stop = 0;
		cudaMemcpy(d_stop, &h_stop, sizeof(int), cudaMemcpyHostToDevice);

		if (no_of_nodes > 0)
		{
			int threads = 256;
			int blocks = (no_of_nodes + threads - 1) / threads;

			bfs_kernel_phase1<<<blocks, threads>>>(
				no_of_nodes,
				d_graph_nodes,
				d_graph_edges,
				d_graph_mask,
				d_updating_graph_mask,
				d_graph_visited,
				d_cost);

			bfs_kernel_phase2<<<blocks, threads>>>(
				no_of_nodes,
				d_graph_mask,
				d_updating_graph_mask,
				d_graph_visited,
				d_stop);
		}

		int h_stop_out = 0;
		cudaMemcpy(&h_stop_out, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
		stop = (h_stop_out != 0);
		k++;
	}
	while(stop);

	cudaDeviceSynchronize();
	auto end_time = std::chrono::high_resolution_clock::now();
	double elapsed =
		std::chrono::duration_cast<std::chrono::duration<double> >(end_time - start_time).count();
	printf("Compute time: %lf\n", elapsed);

	if (no_of_nodes > 0)
		cudaMemcpy(h_cost, d_cost, sizeof(int) * no_of_nodes, cudaMemcpyDeviceToHost);

	FILE *fpo = fopen("result.txt","w");
	for(int i = 0; i < no_of_nodes; i++)
		fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n");

	free(h_graph_nodes);
	free(h_graph_edges);
	free(h_graph_mask);
	free(h_updating_graph_mask);
	free(h_graph_visited);
	free(h_cost);

	if (d_graph_nodes) cudaFree(d_graph_nodes);
	if (d_graph_edges) cudaFree(d_graph_edges);
	if (d_graph_mask) cudaFree(d_graph_mask);
	if (d_updating_graph_mask) cudaFree(d_updating_graph_mask);
	if (d_graph_visited) cudaFree(d_graph_visited);
	if (d_cost) cudaFree(d_cost);
	if (d_stop) cudaFree(d_stop);
}
